mapper.update:
UPDATE TASK SET 
	TASKSTARTDATE = TO_DATE(#{taskStartDate, jdbcType=VARCHAR}, 'YYYY-MM-DD'),
	TASKENDDATE = TO_DATE(#{taskEndDate, jdbcType=VARCHAR}, 'YYYY-MM-DD'),
	TASKSTATUS = #{taskStatus}
WHERE TASKID = #{taskId}

UPDATE EMPTASK SET 
	EMPID = #{empId}
WHERE TASKID = #{taskId}

mapper.select:
SELECT t.taskId, t.stageId, s.projectId, t.taskTitle, t.taskDescription, TO_CHAR(t.taskStartDate, 'YYYY-MM-DD') AS taskStartDate, TO_CHAR(t.taskEndDate, 'YYYY-MM-DD') AS taskEndDate, t.taskStatus, t.taskcreator, TO_CHAR(t.taskCreatedDate, 'YYYY-MM-DD') AS taskCreatedDate, s.stgTitle, s.sequence, e1.NAME AS taskCreaterName, e2.NAME AS name FROM TASK t LEFT JOIN STAGE s ON t.stageId = s.stageId LEFT JOIN EMPLOYEE2 e1 ON t.taskcreator = e1.empId LEFT JOIN EMPTASK ep ON t.taskId = ep.taskId LEFT JOIN EMPLOYEE2 e2 ON ep.empId = e2.empId WHERE s.PROJECTID = #{projectId}
AND
ORDER BY s.sequence ASC, t.taskStartDate ASC OFFSET #{offset} ROWS FETCH FIRST #{size} ROWS ONLY
